SELECT
    multiIf(
        target_address = '0x000000000000000000000000000000000000000b', 'g1add',
        target_address = '0x000000000000000000000000000000000000000c', 'g1mul',
        target_address = '0x000000000000000000000000000000000000000d', 'g1multiexp',
        target_address = '0x000000000000000000000000000000000000000e', 'g2add',
        target_address = '0x000000000000000000000000000000000000000f', 'g2mul',
        target_address = '0x0000000000000000000000000000000000000010', 'g2multiexp',
        target_address = '0x0000000000000000000000000000000000000011', 'pairing',
        target_address = '0x0000000000000000000000000000000000000012', 'map_fp_to_g1',
        target_address = '0x0000000000000000000000000000000000000013', 'map_fp2_to_g2',
        'unknown'
    ) AS precompile,
    gas AS gas_value,
    count() AS call_count,
    round(count() * 100.0 / sum(count()) OVER (PARTITION BY precompile), 4) AS pct
FROM mainnet.int_transaction_call_frame FINAL
WHERE block_number BETWEEN 24120001 AND 24546241
    AND target_address IN (
        '0x000000000000000000000000000000000000000b',
        '0x000000000000000000000000000000000000000c',
        '0x000000000000000000000000000000000000000d',
        '0x000000000000000000000000000000000000000e',
        '0x000000000000000000000000000000000000000f',
        '0x0000000000000000000000000000000000000010',
        '0x0000000000000000000000000000000000000011',
        '0x0000000000000000000000000000000000000012',
        '0x0000000000000000000000000000000000000013'
    )
GROUP BY precompile, gas_value
ORDER BY precompile, call_count DESC
